function openModal(id) {
  const p = profiles[id];
  if (!p) return;
  const interestTags = p.interests.map(i => `<span class="modal-tag">${i}</span>`).join('');
  const approachTags = p.approaches.map(a => `<span class="modal-tag">${a}</span>`).join('');
  document.getElementById('modalContent').innerHTML = `
    <button class="modal-close" onclick="closeModal()">✕</button>
    ${p.photo ? `<div class="modal-avatar" style="background:${p.grad};padding:0;overflow:hidden;"><img src="${p.photo}" style="width:100%;height:100%;object-fit:cover;object-position:top center;"></div>` : `<div class="modal-avatar" style="background:${p.grad}">${p.initials}</div>`}
    <div class="modal-name">${p.name}</div>
    <div class="modal-role">${p.role}</div>
    <div class="modal-section">
      <div class="modal-section-title">About</div>
      <p>${p.bio}</p>
    </div>
    ${p.ages ? `<div class="modal-section">
      <div class="modal-section-title">Ages</div>
      <p>${p.ages}</p>
    </div>` : ''}
    <div class="modal-section">
      <div class="modal-section-title">Areas of Interest</div>
      <div class="modal-tags">${interestTags}</div>
    </div>
    <div class="modal-section">
      <div class="modal-section-title">Therapeutic Approaches</div>
      <div class="modal-tags">${approachTags}</div>
    </div>
    <div class="modal-section">
      <div class="modal-section-title">Availability</div>
      <div class="modal-avail">${p.avail}</div>
    </div>
    <a href="https://clientportal.zandahealth.com/clientportal/hzyb6/home" target="_blank" rel="noopener" class="btn-primary" style="display:inline-block;margin-top:8px;" onclick="closeModal(); window.open('https://clientportal.zandahealth.com/clientportal/hzyb6/home', '_blank')">Book with ${p.name.split(' ')[0]}</a>
  `;
  document.getElementById('modalOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeModal(e) {
  if (e && e.target !== document.getElementById('modalOverlay')) return;
  document.getElementById('modalOverlay').classList.remove('open');
  document.body.style.overflow = '';
}

function filterTeam(tag, btn) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.querySelectorAll('.team-card').forEach(card => {
    if (tag === 'all') { card.style.display = ''; return; }
    const tags = card.dataset.tags || '';
    const match =
      (tag === 'clinical' && (tags.includes('clinical') || tags.includes('director'))) ||
      (tag === 'registered' && tags.includes('registered') && !tags.includes('director') && !tags.includes('clinical')) ||
      (tag === 'provisional' && tags.includes('provisional')) ||
      (tag === 'children' && tags.includes('children')) ||
      (tag === 'trauma' && tags.includes('trauma'));
    card.style.display = match ? '' : 'none';
  });
}

(function () {
  const btn = document.getElementById('soundBtn');
  const video = document.getElementById('heroVideo');
  if (!btn || !video) return;

  btn.addEventListener('click', function () {
    video.muted = !video.muted;
    const on = !video.muted;
    btn.querySelector('.icon-mute').style.display = on ? 'none' : '';
    btn.querySelector('.icon-sound').style.display = on ? '' : 'none';
    btn.querySelector('.sound-label').textContent = on ? 'Mute' : 'Enable Sound';
    btn.classList.toggle('is-on', on);
  });
})();

(function () {
  const nav = document.querySelector('nav');
  const threshold = window.innerHeight * 0.1;
  function onScroll() {
    nav.classList.toggle('scrolled', window.scrollY > threshold);
  }
  window.addEventListener('scroll', onScroll, { passive: true });
  onScroll();
})();

(function () {
  const pb = document.querySelector('.page-body');
  const hc = document.querySelector('.hero-content');
  if (!pb || !hc) return;

  function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
  function clamp(v, lo, hi) { return Math.min(Math.max(v, lo), hi); }

  let ticking = false;
  function render() {
    const s   = window.scrollY;
    const vh  = window.innerHeight;
    const pbP = easeOutCubic(clamp(s / (vh * 0.35), 0, 1));

    hc.style.opacity = '1';
    hc.style.transform = 'translateY(0px)';
    pb.style.transform    = `translateY(${(90 * (1 - pbP)).toFixed(2)}px) scale(${(0.985 + 0.015 * pbP).toFixed(4)})`;
    pb.style.borderRadius = `${(48 - 20 * pbP).toFixed(1)}px ${(48 - 20 * pbP).toFixed(1)}px 0 0`;
    ticking = false;
  }

  function onScroll() {
    if (!ticking) {
      requestAnimationFrame(render);
      ticking = true;
    }
  }

  window.addEventListener('scroll', onScroll, { passive: true });
  render();
})();
